import React from 'react';

const Navbar = ({ active, setActive, onGoHome }) => {
  // Removemos "Agendamentos" da lista de botões clicáveis
  const menuItems = ["Início", "Serviços", "Contato"];

  const handleScroll = (item) => {
    setActive(item);
    const sectionId = item.toLowerCase();
    const element = document.getElementById(sectionId);
    if (element) {
      element.scrollIntoView({ behavior: 'smooth' });
    }
  };

  return (
    <nav className="pb-navbar" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
      <div className="pb-brand">
        <div className="pb-logo-wrap">
          <div className="pb-logo">
            <span className="pb-logo-text">PB</span>
          </div>
        </div>
        <div className="pb-brand-name">
          <span>Palheta</span>
          <span>Barbearia</span>
        </div>
      </div>

      {/* TEXTO CENTRALIZADO, GRANDE E DESTACADO */}
      <div style={{
        position: 'absolute',
        left: '50%',
        transform: 'translateX(-50%)',
        textAlign: 'center'
      }}>
        <h2 style={{
          fontFamily: 'Cormorant Garamond, serif',
          color: 'var(--amarelo)',
          fontSize: '28px',
          letterSpacing: '3px',
          textTransform: 'uppercase',
          margin: 0,
          fontWeight: '700',
          textShadow: '2px 2px 4px rgba(0,0,0,0.3)'
        }}>
          Agendamento do Cliente
        </h2>
      </div>

      <ul className="pb-nav-links">
        {/* BOTÃO HOME (VOLTAR) */}
        <li>
          <button 
            onClick={onGoHome} 
            className="pb-nav-link"
            style={{ 
              color: 'var(--amarelo)', 
              fontWeight: 'bold',
              border: '1px solid var(--amarelo)',
              padding: '5px 15px',
              borderRadius: '4px'
            }}
          >
            ← VOLTAR
          </button>
        </li>

        {menuItems.map((item) => (
          <li key={item}>
            <button
              onClick={() => handleScroll(item)}
              className={`pb-nav-link ${active === item ? "active" : ""}`}
            >
              {item}
            </button>
          </li>
        ))}
      </ul>
    </nav>
  );
};

export default Navbar;
